// CATALOG: map each dropdown option -> brand productId, card slot, denominations.
// ADD NEW VOUCHERS/BRANDS HERE (e.g. Swiggy) — just add a line; the dropdown option label must match.
const CARD_SLOT = { charge: 0, mrcc: 1 }; // PayU saved-card slots
const CATALOG = {
  'Amazon Pay ₹1,000 — Gold Charge':      { brand: 'amazonpay', productId: 'gko2OEEac6Y24dmH/bBa7g==', card: 'charge', denominations: [{ amount: 1000, qty: 1 }] },
  'Amazon Pay ₹1,500 — MRCC (1000+500)':  { brand: 'amazonpay', productId: 'gko2OEEac6Y24dmH/bBa7g==', card: 'mrcc',   denominations: [{ amount: 1000, qty: 1 }, { amount: 500, qty: 1 }] },
  'Amazon Pay ₹2,500 — MRCC':             { brand: 'amazonpay', productId: 'gko2OEEac6Y24dmH/bBa7g==', card: 'mrcc',   denominations: [{ amount: 2500, qty: 1 }] },
  'Amazon Pay ₹5,000 — MRCC':             { brand: 'amazonpay', productId: 'gko2OEEac6Y24dmH/bBa7g==', card: 'mrcc',   denominations: [{ amount: 5000, qty: 1 }] },
  'Swiggy ₹1,000 — Gold Charge':          { brand: 'swiggy',    productId: '67QXkJBH5ual2f8tm2sCvQ==', card: 'charge', denominations: [{ amount: 1000, qty: 1 }] },
  'Swiggy ₹1,500 — MRCC (1000+500)':      { brand: 'swiggy',    productId: '67QXkJBH5ual2f8tm2sCvQ==', card: 'mrcc',   denominations: [{ amount: 1000, qty: 1 }, { amount: 500, qty: 1 }] },
  'Swiggy ₹2,000 — MRCC':                 { brand: 'swiggy',    productId: '67QXkJBH5ual2f8tm2sCvQ==', card: 'mrcc',   denominations: [{ amount: 2000, qty: 1 }] }
};

const f = $input.first().json;
const choice = f['What do you want to buy?'];
const count = Math.max(1, parseInt(f['How many transactions?'] || '1', 10) || 1);
const dryRun = String(f['Mode'] || '').toLowerCase().includes('dry');

const c = CATALOG[choice];
if (!c) throw new Error('Unknown selection: ' + choice);
const plan = {
  brands: { [c.brand]: c.productId },
  cards:  { [c.card]: CARD_SLOT[c.card] },
  jobs:   [ { name: choice, card: c.card, brand: c.brand, denominations: c.denominations, count } ]
};
return [{ json: { dryRun, plan, choice, count } }];
